import boto3
from botocore.exceptions import NoCredentialsError, EndpointConnectionError, BotoCoreError

def poll_sqs():
    sqs = boto3.client('sqs')
    
    try:
        response = sqs.receive_message(
            QueueUrl='<YOUR_QUEUE_URL>',  # replace with your SQS queue url
            MaxNumberOfMessages=1,
            WaitTimeSeconds=0  # the duration to wait for messages (long polling)
        )
        
        if 'Messages' in response:
            message = response['Messages'][0]
            
            receipt_handle = message['ReceiptHandle']
                
            # You can parse and process the message here, based on its content. 
            print(f"Received message: {message['Body']}")
             
            # Then delete the processed messages from SQS queue
            sqs.delete_message(QueueUrl='<YOUR_QUEUE_URL>', ReceiptHandle=receipt_handle) 
            
    except NoCredentialsError:
        print("No AWS Credentials found")
    except EndpointConnectionError:
        print("Unable to connect to SQS endpoint")
    except BotoCoreError as e:
        print(f"Boto3 error occurred: {e}")